93	
94	  // --- Modifier thresholds ---
95	  it("customer with exactly 2 years gets loyalty discount (plain sword, 1st contract) → 100 - 20 loy + 10 first-ins + 5 fee = 95 G", () => {
96	    const out = run({
97	      customer: { yearsWithMHPCO: 2 },
98	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
