109	
110	  // --- Multi-item policy & modifier scope ---
111	  it("cursed sword + plain amulet (new customer, 1st contract) → 100+60 base, cursed adds 50 (of sword only), first-ins 10% of policy total → 160 + 50 + 16 + 5 = 231 G", () => {
112	    const out = run({
113	      customer: { yearsWithMHPCO: 0 },
114	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }, { type: "amulet" }] }],
115	    });
116	    expect(out).toEqual({ results: [{ premium: 231 }] });
