118	
119	  // --- Follow-up contract discount (15% on each contract after first) ---
120	  it("second quote in scenario: cursed sword + plain amulet, 0 years → 160 base + 50 curse + 16 first-ins - 24 follow-up + 5 fee = 207 G", () => {
121	    const out = run({
122	      customer: { yearsWithMHPCO: 0 },
123	      steps: [
124	        { op: "quote", items: [{ type: "sword" }] },
125	        { op: "quote", items: [{ type: "sword", cursed: true }, { type: "amulet" }] },
126	      ],
127	    });
128	    expect(out).toEqual({ results: [{ premium: 115 }, { premium: 207 }] });
