130	
131	  // --- Integration examples ---
132	  it("newcomer cursed sword (0 years, no prior): 100 + 50 + 10 + 5 = 165 G", () => {
133	    const out = run({
134	      customer: { yearsWithMHPCO: 0 },
135	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
136	    });
137	    expect(out).toEqual({ results: [{ premium: 165 }] });
138	  });
139	  it.todo("long-standing customer's 2nd contract, cursed enchantment-7 sword (3 years): 100 + 50 + 30 - 20 + 10 - 15 + 5 = 160 G");
140	
141	  // --- Rounding in MHPCO's favor ---
142	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
143	
144	  // --- Claim: basic deductible & standard reimbursement ---
145	  it.todo("steel sword enchantment 3, damage 500 → payout 400 (500 - 100 deductible)");
146	  it.todo("damage to a rune (250 G), damage 200 → payout 100 (200 - 100 deductible)");
147	
148	  // --- Claim: high-enchantment 50% clause ---
149	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 (50% then deductible: 500 - 100)");
150	
151	  // --- Claim: dragon material full reimbursement ---
152	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
153	
154	  // --- Claim: dragon + high enchantment combined (50% wins) ---
155	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-ench applies first then deductible)");
156	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
157	
158	  // --- Claim: deductible per damage event ---
159	  it.todo("dragon attack damages insured sword 500 and amulet 300 → payout 600 (deductible applies once per damaged item)");
160	
161	  // --- Multiple items of same type ---
162	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; two sword damage entries each get own deductible");
163	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero (claim rejected)");
164	
165	  // --- Cap exhaustion ---
166	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
167	  it.todo("cursed sword cap is 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
168	  it.todo("sword + 3 runes block: insurance sum 1750 G (block discount affects premium only, not insurance sum)");
169	  it.todo("sword (cap 2000): claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
170	
171	  // --- Rounding payout ---
172	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
173	
174	  // --- Error cases ---
175	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with error to stderr");
176	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
177	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
178	});
