1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Input = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
8	const CURSE_SURCHARGE_PERCENT = 50;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
11	const LOYALTY_THRESHOLD_YEARS = 2;
12	const LOYALTY_DISCOUNT_PERCENT = 20;
13	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PREMIUM = 60;
16	
17	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const groupBaseAmount = (type: string, count: number): number => {
29	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
30	    return COMPONENT_BLOCK_PREMIUM;
31	  }
32	  return count * BASE_PREMIUM_BY_TYPE[type];
33	};
34	
35	const countByType = (items: Item[]): Map<string, number> =>
36	  items.reduce(
37	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
38	    new Map<string, number>(),
39	  );
40	
41	const basePremium = (items: Item[]): number =>
42	  Array.from(countByType(items)).reduce(
43	    (total, [type, count]) => total + groupBaseAmount(type, count),
44	    0,
45	  );
46	
47	const percentOf = (amount: number, percent: number): number =>
48	  (amount * percent) / 100;
49	
50	const percentOfItemBase = (item: Item, percent: number): number =>
51	  percentOf(BASE_PREMIUM_BY_TYPE[item.type], percent);
52	
53	const firstInsuranceSurcharge = (base: number): number =>
54	  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));
55	
56	type ItemSurchargeRule = { applies: (item: Item) => boolean; percent: number };
57	
58	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
59	  { applies: (item) => item.cursed === true, percent: CURSE_SURCHARGE_PERCENT },
60	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT },
61	];
62	
63	const surchargesForItem = (item: Item): number =>
64	  ITEM_SURCHARGE_RULES.reduce(
65	    (sum, { applies, percent }) => sum + (applies(item) ? percentOfItemBase(item, percent) : 0),
66	    0,
67	  );
68	
69	const itemSurcharges = (items: Item[]): number =>
70	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
71	
72	const loyaltyDiscount = (base: number, customer: Customer): number =>
73	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
74	    ? percentOf(base, LOYALTY_DISCOUNT_PERCENT)
75	    : 0;
76	
77	const followupContractDiscount = (base: number, stepIndex: number): number =>
78	  stepIndex > 0 ? percentOf(base, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT) : 0;
79	
80	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
81	  const base = basePremium(items);
82	  const surcharges = itemSurcharges(items) + firstInsuranceSurcharge(base);
83	  const discounts = loyaltyDiscount(base, customer) + followupContractDiscount(base, stepIndex);
84	  return base + surcharges - discounts + PROCESSING_FEE;
85	};
86	
87	const executeStep = (customer: Customer) => ({ items }: Step, stepIndex: number) => ({
88	  premium: quotePremium(items, customer, stepIndex),
89	});
90	
91	export const run = (input: unknown): unknown => {
92	  const { customer, steps } = input as Input;
93	  return { results: steps.map(executeStep(customer)) };
94	};
